"""
OrangeTree Global — Social Content Generator (UC4)
Powered by Claude API (Anthropic)
Run: streamlit run uc4_social_content.py
"""

import streamlit as st
import anthropic
import json

LOGO_B64 = ""
LOGO_HTML = '<img src="data:image/svg+xml;base64,' + LOGO_B64 + '" style="width:100%;max-width:220px;display:block;margin-bottom:4px;">'

st.set_page_config(
    page_title="Social Content Generator | OrangeTree Global",
    page_icon="🌳",
    layout="wide",
)

st.markdown("""
<style>
    .post-card {
        background: #f8f9fa;
        border-left: 4px solid #F36621;
        padding: 1rem 1.2rem;
        border-radius: 4px;
        margin: 0.5rem 0;
        white-space: pre-wrap;
        font-size: 0.95rem;
        line-height: 1.75;
    }
    .platform-label {
        font-weight: 600;
        font-size: 0.85rem;
        color: #F36621;
        text-transform: uppercase;
        letter-spacing: 0.05em;
        margin-bottom: 4px;
    }
    .section-header {
        border-left: 4px solid #F36621;
        padding: 0.3rem 0.8rem;
        background: #fff3ee;
        border-radius: 0 4px 4px 0;
        margin: 1.2rem 0 0.6rem 0;
        font-weight: 600;
    }
    .char-count {
        font-size: 0.78rem;
        color: #888;
        margin-top: 4px;
    }
</style>
""", unsafe_allow_html=True)

st.markdown(
    f'<img src="data:image/svg+xml;base64,{LOGO_B64}" style="width:280px;max-width:100%;display:block;margin-bottom:12px;">',
    unsafe_allow_html=True
)
st.markdown("## Social Content Generator")
st.markdown("Describe your topic or offer and get ready-to-post content for LinkedIn, Instagram, and Facebook — in your brand voice.")
st.divider()

with st.sidebar:
    st.markdown(LOGO_HTML, unsafe_allow_html=True)
    st.markdown("---")
    api_key = st.text_input("Anthropic API Key", type="password", help="Get from console.anthropic.com")
    model = st.selectbox("Model", ["claude-opus-4-8", "claude-sonnet-4-6", "claude-haiku-4-5-20251001"], index=1)
    st.markdown("---")
    st.markdown("**Your Brand**")
    biz_name = st.text_input("Business / Brand name", placeholder="e.g. OrangeTree Global")
    biz_type = st.selectbox("Business type", [
        "Training & Education", "Restaurant / F&B", "Retail", "Healthcare / Clinic",
        "IT / SaaS", "Consulting / Agency", "Manufacturing", "Other"
    ])
    tone = st.selectbox("Brand tone", [
        "Professional & credible", "Warm & approachable", "Bold & energetic",
        "Witty & conversational", "Inspirational"
    ])
    include_hashtags = st.checkbox("Include hashtags", value=True)
    include_cta = st.checkbox("Include call-to-action", value=True)
    st.markdown("---")
    st.markdown("**Platforms**")
    platforms = st.multiselect("Generate for", ["LinkedIn", "Instagram", "Facebook"],
        default=["LinkedIn", "Instagram"])
    st.markdown("---")
    st.info("UC4 of OrangeTree's AI SME Suite. Powered by Claude API.", icon="ℹ️")

st.markdown('<div class="section-header">What do you want to post about?</div>', unsafe_allow_html=True)

col1, col2 = st.columns([2, 1], gap="large")

with col1:
    topic = st.text_area("Topic / Offer / Announcement",
        height=120,
        placeholder="e.g. We just launched a new 2-day Data Analytics bootcamp for working professionals. Starting July 15. Early bird discount of 20% available until July 5.")

    extras = st.text_area("Any specific points to include (optional)",
        height=80,
        placeholder="e.g. Mention the weekend batch option. Highlight that no coding experience needed. Include our website orangetreeglobal.com")

with col2:
    st.markdown("**Batch mode — generate multiple topics**")
    batch_mode = st.checkbox("Generate for multiple topics at once")
    if batch_mode:
        batch_topics = st.text_area("One topic per line",
            height=120,
            placeholder="Topic 1\nTopic 2\nTopic 3")

num_variants = st.selectbox("Variants per platform", [1, 2, 3], index=0,
    help="Generate 2-3 options so you can pick the best one")

generate_btn = st.button("Generate Content", type="primary", use_container_width=False,
    disabled=(not topic.strip() and not (batch_mode and batch_topics.strip())))

if not platforms:
    st.warning("Select at least one platform in the sidebar.")

if generate_btn and platforms:
    if not api_key:
        st.error("Enter your Anthropic API key in the sidebar.")
        st.stop()

    topics_to_process = []
    if batch_mode and batch_topics.strip():
        topics_to_process = [t.strip() for t in batch_topics.strip().split("\n") if t.strip()]
    elif topic.strip():
        topics_to_process = [topic.strip()]

    if not topics_to_process:
        st.warning("Enter at least one topic.")
        st.stop()

    client = anthropic.Anthropic(api_key=api_key)

    hashtag_instruction = "Include 5-8 relevant hashtags at the end." if include_hashtags else "Do NOT include hashtags."
    cta_instruction = "End with a clear call-to-action." if include_cta else "No call-to-action needed."

    PLATFORM_SPECS = {
        "LinkedIn": "Professional tone, 150-300 words, storytelling hook, business audience, line breaks for readability.",
        "Instagram": "Visual and punchy, 80-150 words, emojis welcome, engaging opening line, mobile-first.",
        "Facebook": "Conversational, 100-200 words, community feel, encourage comments or shares.",
    }

    for t_idx, t in enumerate(topics_to_process):
        if len(topics_to_process) > 1:
            st.markdown(f"### Topic {t_idx+1}: {t[:60]}{'...' if len(t) > 60 else ''}")

        for platform in platforms:
            st.markdown(f'<div class="platform-label">{platform}</div>', unsafe_allow_html=True)

            with st.spinner(f"Writing {platform} post..."):
                try:
                    system = f"""You are a social media content expert for {biz_name or 'this business'}, a {biz_type} brand.
Brand tone: {tone}.
Write ONLY the post text — no commentary, no labels, no 'Here is your post:'.
{PLATFORM_SPECS.get(platform, '')}
{hashtag_instruction}
{cta_instruction}
If generating multiple variants, separate them with ---VARIANT--- on its own line."""

                    user_msg = f"Topic: {t}"
                    if extras.strip():
                        user_msg += f"\nAdditional points: {extras}"
                    if num_variants > 1:
                        user_msg += f"\nGenerate {num_variants} different variants."

                    response = client.messages.create(
                        model=model,
                        max_tokens=1500,
                        system=system,
                        messages=[{"role": "user", "content": user_msg}]
                    )

                    raw = response.content[0].text.strip()
                    variants = raw.split("---VARIANT---") if "---VARIANT---" in raw else [raw]

                    for v_idx, variant in enumerate(variants):
                        variant = variant.strip()
                        if len(variants) > 1:
                            st.markdown(f"*Variant {v_idx + 1}*")
                        st.markdown(f'<div class="post-card">{variant}</div>', unsafe_allow_html=True)
                        st.markdown(f'<div class="char-count">{len(variant)} characters</div>', unsafe_allow_html=True)
                        st.code(variant, language=None)

                except Exception as e:
                    st.error(f"{platform} error: {e}")

            st.markdown("")

        if t_idx < len(topics_to_process) - 1:
            st.divider()

st.caption("OrangeTree Global | AI SME Suite — UC4: Social Content Generator")
